// Place mines
for "_i" from 1 to _numMines do {
    // Generate random position within the specified radius
    _randomPos = _centerPos findEmptyPosition [0, _radius, 10];

    // Create a mine for the generated position
    _mine = createVehicle ["APERSLandMine_Range_Ammo_Pack", _randomPos, [], 0, "NONE"];

    // Uncomment below line if you want the mines to be "activated" by default when spawned
    //_mine setDamage 0;
};
```

